function makeTestQ(id, type, hindi, options, answer, explanation, sentence = null, correct = null) {
  const q = { id, type };
  if (type === 'translate') q.hindi = hindi;
  if (type === 'error' || type === 'fill') { q.sentence = sentence || hindi; }
  if (type === 'error') q.correct = correct;
  q.options = options;
  q.answer = answer;
  q.explanation = explanation;
  return q;
}

