function buildVocabEntry(v, id) {
  return {
    id,
    word: v.w,
    hindi: v.h,
    simpleMeaning: v.s,
    ipa: v.ipa,
    verbForms: {
      base: v.vf.base,
      s3: v.vf.s3,
      ing: v.vf.ing,
      past: v.vf.past,
      pastParticiple: v.vf.pp
    },
    synonyms: v.syn,
    antonyms: v.ant,
    sentences: {
      daily: v.d.daily,
      office: v.d.office,
      interview: v.d.interview,
      business: v.d.business,
      formal: v.d.formal,
      informal: v.d.informal
    },
    usageNote: v.note,
    cefrLevel: v.cefr
  };
}

const vocabEntries = allVocab.map((v, i) => buildVocabEntry(v, i + 1));

